var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>캄파멘토</color>\\n해발 고도 약 10,000m 지점 <color=#ffd34c>태양이 떠오르는 천공섬</color>","JPN":"管理局直轄都市<color=#ffd34c>カンパメント</color>\\n標高約10,000m地点、<color=#ffd34c>太陽が昇る天空島</color>","ENG":"Administration Direct Control City, <color=#ffd34c>Campamento</color>\\nApprox. 10,000 meters above sea level, <color=#ffd34c>Dawnbreak Floating Island</color>","TWN":"管理局直轄市<color=#ffd34c>坎帕門托</color>\\n海拔約10,000公尺處 <color=#ffd34c>日出東方天空島</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"자, 고개를 들어 하늘을 보라, 비로소 종말의 때가 왔으니!","JPN":"さあ、顔を上げ空を見よ！　ついに終末の時が来た！","ENG":"Raise your heads and look to the sky! The time of the end is upon us!","TWN":"來，抬頭仰望天空，終於到了末日之時！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L6_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"신성한 뿌리가 하늘을 덮고, 다시 한 차례 태양빛을 가리게 될 때.","JPN":"神聖な根が空を覆い、再び太陽の光を隠す時。","ENG":"When the sacred root shrouds the heavens and once again eclipses the sun...","TWN":"當神聖的根遮天蔽日，再次擋住陽光時。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"어리석은 이들의 피로 몸을 씻고, 심장 고기를 씹은 우리는 구원을 받으리라!","JPN":"愚か者たちの血で体を洗い、心臓の肉をかじった我らは救われよう！","ENG":"We who bathe in the blood of fools and feast upon their hearts shall be saved!","TWN":"用愚者的血洗淨身體，咀嚼心臟的我們將獲得救贖！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"죽여라! 죽여라! 죽여라! 죽여라!","JPN":"殺せ！　殺せ！　殺せ！　殺せ！","ENG":"Kill! Kill! Kill! Kill!","TWN":"殺了他！殺了他！殺了他！殺了他！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"어리석은 이들에게 죽음을……! 그들의 피와 심장을……!","JPN":"愚か者に死を……！　彼らの血と心臓を……！","ENG":"Death to the foolish...! Their blood and hearts...!","TWN":"愚蠢的人，去死吧……！用他們的血和心臟……！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"오오──!","JPN":"おおお──！","ENG":"Ooooh──!","TWN":"喔喔──！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"<color=#ffd34c>신목</color>님께서 우리의 기도에 응답하셨다!","JPN":"<color=#ffd34c>神木</color>様が我らの祈りに応えてくださった！","ENG":"The <color=#ffd34c>Sacred Tree</color> has answered our prayers!","TWN":"<color=#ffd34c>神木</color>回應了我們的祈禱！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"포획한 제물을 신목님께 바쳐라!","JPN":"捕獲した生贄を神木様に捧げろ！","ENG":"Offer the captured sacrifice to the Sacred Tree!","TWN":"將捕獲的祭品獻給神木！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"으, 으아아아…….","JPN":"う、うわああ……","ENG":"Urgh... ughhhh...","TWN":"呃，呃啊啊啊……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"이, 이러지 마…! 살려줘, 살려달라고……!","JPN":"や、やめろ……！　助けて、助けてくれ……！","ENG":"D-don't do this...! Please, spare me...!","TWN":"不，不要這樣……！救命，拜託救救我……！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"아니, 차라리 죽여줘! 살아있는 채로 먹히고 싶지는 않아……!","JPN":"いや、いっそのこと殺してくれ！　生きたまま食われたくない……！","ENG":"No, just kill me! I don't want to be eaten alive...!","TWN":"不，快殺了我吧！我不想活著被吃掉……！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"으, 으, 으아아, 으아아아아아악──!!","JPN":"う、う、うああ、うわあああああ──！！","ENG":"Uh, ahhh, AHHHHHHH──!!","TWN":"呃，呃，呃啊啊，呃啊啊啊啊啊啊──！！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"죽여라! 죽여라! 죽여라! 죽여라!","JPN":"殺せ！　殺せ！　殺せ！　殺せ！","ENG":"Kill! Kill! Kill! Kill!","TWN":"殺了他！殺了他！殺了他！殺了他！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L25_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"어리석은 이들에게 죽음을……! 그들의 피와 심장을……!","JPN":"愚か者に死を……！　彼らの血と心臓を……！","ENG":"Death to the foolish...! Their blood and hearts...!","TWN":"愚蠢的人，去死吧……！用他們的血和心臟……！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"큭, 그렇게 솎아낸다고 솎아냈건만…….","JPN":"くっ、あれだけあぶり出したというのに……","ENG":"Kgh, even after culling them over and over...","TWN":"唔，明明已經除掉那麼多……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"학회의 잔존 세력이 아직도 천공섬에 남아 있을 줄이야…….","JPN":"学会の残存勢力がまだ天空島に残っていたとは……","ENG":"To think remnants of the Society still lingered on this floating island...","TWN":"沒想到學會的殘餘勢力還留在天空島上……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"대장님…! 이제 우리는 어떻게 해야 합니까……?","JPN":"隊長……！　これからどうすればいいんですか……？","ENG":"Captain...! What do we do now...?","TWN":"隊長…！現在我們該怎麼辦……？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"이제 우리 밖에 안 남았다고요…! 저는 아직 죽고 싶지 않습니다……!","JPN":"残りは私たちだけです……！　私はまだ死にたくありません……！","ENG":"We're all that's left...! I don't want to die yet...!","TWN":"現在只剩下我們了……！我還不想死……！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"시끄러워! 누군 죽고 싶은 줄 알아!?","JPN":"うるさい！　俺だって死にたくないんだよ！","ENG":"Shut up! You think I want to die?!","TWN":"吵死了！誰想死啊！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"조금만, 조금만 더 기다리면… 웨이드 님께서 오실 거야……!","JPN":"あと少し、あと少しだけ持ちこたえれば……ウェイド様が来てくださるはずだ……！","ENG":"Just a little longer... Sir Wade will come to our rescue...!","TWN":"再等一下，再等一下……韋德會來的……！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"그, 그렇지만 웨이드 님께서는 VIP를 보러 가신 뒤로 돌아오지 않으셨잖아요!","JPN":"で、ですがウェイド様はVIPのところに向かってから帰ってこられてないんですよ！","ENG":"B-but Sir Wade hasn't returned since he went to see the VIP!","TWN":"可，可是韋德去見VIP後就沒回來啦！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"지금까지 아무런 소식이 없는 걸 보면, 아마도…….","JPN":"いまだ音沙汰がないってことは、おそらく……","ENG":"If there's still no word by now, then maybe he's already–","TWN":"到現在都沒有任何消息，我看……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"닥쳐! 그 분은 캄파멘토의 공인 카운터야…! 그렇게 쉽게 당할 리가……","JPN":"黙れ！　あの方はカンパメントの公認カウンターだ……！　そう簡単にやられるわけが……","ENG":"Shut it! He's Campamento's Official Counter...! He wouldn't fall so easily...","TWN":"閉嘴！那位可是坎帕門托的公認制裁者……！不可能那麼輕易就被打倒……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"쉿─!","JPN":"しーっ！","ENG":"Shhh─!","TWN":"噓─！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"구하러 왔습니데이, 이젠 안심하이소.","JPN":"助けに来たさかい、もう安心してええで。","ENG":"We're here to get you out. Y'all can relax now.","TWN":"我們是來救你們的，現在可以放心哩。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"사, 살았다! 감사합니다! 감사합니다!","JPN":"た、助かった！　ありがとうございます、ありがとうございます！","ENG":"We're saved! Thank you, thank you!","TWN":"得救了！謝謝！謝謝！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"상황은 얼추 파악하고 있습니다. 칸 영감님이랑 같이 왔던 탐험대 분들 맞지예?","JPN":"状況は大体把握しとる。あんたたち、カンのじじいと一緒に来た探検隊やろ？","ENG":"I've got a fair grasp of the situation. You're with the expedition old man Khan came with, right?","TWN":"情況已大致瞭解。你們是和坎老頭一起來的探險隊吧？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"사태가 촉박합니다. 영감님은 지금 어디 계신지 아십니까?","JPN":"急いでんねん。じじいの居場所は分かるか？","ENG":"Time's short. Do you know where he is now?","TWN":"事態緊急。你知道坎老頭現在在哪裡嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"아마도 공인 카운터 님과 함께 계실 겁니다.","JPN":"おそらく公認カウンターの方と一緒だと思います。","ENG":"He's likely with the Official Counter.","TWN":"可能和公認制裁者在一起。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"탐험에 성과가 없어서, 복귀하려는 순간 대균열 확장이 시작됐거든요.","JPN":"探検に来たもののこれといった成果がなく、帰還しようとした瞬間大亀裂が拡張しはじめて。","ENG":"They were about to turn back after the expedition came up empty when the Grand Dimension Crevice expansion began.","TWN":"這次探險沒有得到成果，當我們正準備返回時，大峽谷開始擴張。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"캄파멘토 공인 카운터라카면…….","JPN":"カンパメントの公認カウンターということは……","ENG":"Campamento's Official Counter, huh...","TWN":"坎帕門托公認制裁者……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그래, 바르거스 가문 사람이 같이 있다카믄, 당장은 괜찮을지도……","JPN":"そうか。バルガス家の人が一緒やったら、しばらくは大丈夫そうやな。","ENG":"If someone from the Vargas family is with him, he should be safe for now...","TWN":"如果和巴克斯家族的人在一起的話，暫時應該不會有事……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"흑, 흐윽…! 여러분……!","JPN":"うっ、うう……！　皆さん……！","ENG":"*Sob* *Sniffle...!* Everyone...!","TWN":"嗚嗚……！大家……！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"하하… 이거 기적이군요…….","JPN":"はは……これは、奇跡としか言いようがありませんね……","ENG":"Haha... This is a miracle...","TWN":"哈哈……這真是個奇蹟……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"살아서 시타 아가씨를 다시 보게 될 줄이야…….","JPN":"生きてシータお嬢様にもう一度お会いできるとは……","ENG":"To think I'd live to see Lady Sita again...","TWN":"沒想到還能活著再見到悉多小姐……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"……시타 아가씨께서도 대원 분들이 살아 계셔서 무척 기뻐하십니다.","JPN":"……シータお嬢様も、隊員の方々が無事でとても喜んでいらっしゃいます。","ENG":"...Lady Sita is also overjoyed to see you all alive.","TWN":"……悉多小姐也非常高興隊員們還活著。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"제가 탈출 포인트를 찍어드리죠.","JPN":"脱出ポイントをお伝えします。","ENG":"I'll mark an extraction point for you.","TWN":"我來為你們標記逃脫點。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L19_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그곳에서 대기하시면, 관리국 본부에서 수송기를 보낼 겁니다.","JPN":"そこで待機すれば、管理局本部から輸送機が来るはずです。","ENG":"Head there and wait. The Administration headquarters will dispatch a transport.","TWN":"請在那邊等待，管理局總部會派運輸機過來。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"감사합니다, 감사합니다!","JPN":"本当にありがとうございます！","ENG":"Thank you, thank you!","TWN":"謝謝，謝謝！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L25_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"그래도 생존자를 구할 수 있어서 다행이에요.","JPN":"でも、生存者を助けることができてよかったです。","ENG":"At least we managed to save some survivors.","TWN":"幸好能救到倖存者。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"이래저래 운이 좋았데이. 사교도 놈들, 의식에 완전 정신 팔려 있더만.","JPN":"まあ運がよかったな。邪教徒のやつら、儀式に夢中やったし。","ENG":"Lucky break all around. Those cultists were too wrapped up in their ritual.","TWN":"看來運氣不錯。那些邪教徒完全沉浸在他們的儀式中。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그라모 로빈, 이제 우리도 할 일 해야제.","JPN":"さて、ロビン。ウチらもやることやらな。","ENG":"But Robin, we've got work to do.","TWN":"蘿蘋，該做事囉。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"시타 님, 두 번째 아티팩트에 관한 단서… 틀림없는 거지예?","JPN":"シータさん、2つ目のアーティファクトの手がかり……間違いないですか？","ENG":"Lady Sita, the clue about the second Artifact... You're sure of it, right?","TWN":"悉多小姐，關於第二個人造神器的線索……是正確的吧？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>눈먼 자들이 숭배하는 자의 거짓된 얼굴</color>.","JPN":"<color=#ffd34c>盲目の者たちが崇める偽りの顔</color>。","ENG":"<color=#ffd34c>The false face worshipped by the blind</color>.","TWN":"<color=#ffd34c>盲目者所崇拜的虛假面孔</color>。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"여기서 눈 먼자라는 건, 결국 저 사교도들을 뜻하겠고…….","JPN":"盲目の者たちはあの邪教徒のことで……","ENG":"The blind must mean those cultists...","TWN":"這裡的盲目者，指的就是那些邪教徒吧……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"거짓된 얼굴이라는 건, 저들이 섬기는 침식체가 쓰고 있는 가면이겠네요.","JPN":"偽りの顔は、彼らが崇拝する侵食体がつけている仮面のことでしょう。","ENG":"And the false face would be the mask worn by the C.O. they serve.","TWN":"所謂虛假的面孔，就是他們所侍奉的侵蝕體所戴的面具吧。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"마, 로빈! 슬슬 오러화 준비해야 쓰겄다!","JPN":"ロビン！　そろそろオーラ化の準備せなあかんで！","ENG":"Robin, get your Aurafication ready!","TWN":"哎，蘿蘋！差不多該準備奧蘿化咧！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_PRIDE"}}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_46"},{"id":"L36_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아무래도 저쪽도 우리를 발견한 것 같으니까 말이제……!","JPN":"どうやらあちらさんにバレてしもうたみたいやから……！","ENG":"Looks like they've noticed us too...!","TWN":"他們好像發現我們了……！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_PRIDE"}}}}]`);export{e as default};